806: // https://data.iana.org/time-zones/theory.html#naming
807: // * A name must not be empty, or contain '//', or start or end with '/'.
808: // * Do not use the file name components '.' and '..'.
809: // * Within a file name component, use only ASCII letters, '.', '-' and '_'.
810: // * Do not use digits, as that might create an ambiguity with POSIX TZ strings.
811: // * A file name component must not exceed 14 characters or start with '-'
812: //
813: // 0-9 and + characters are tolerated to accommodate legacy compatibility names
814: var validTimeZoneCharacters = regexp.MustCompile(`^[A-Za-z\.\-_0-9+]{1,14}$`)
815: 
816: func validateTimeZone(timeZone *string, fldPath *field.Path) field.ErrorList {
817: 	allErrs := field.ErrorList{}
818: 	if timeZone == nil {
819: 		return allErrs
820: 	}
821: 
822: 	if len(*timeZone) == 0 {
823: 		allErrs = append(allErrs, field.Invalid(fldPath, timeZone, "timeZone must be nil or non-empty string"))
824: 		return allErrs
825: 	}
826: 
827: 	for _, part := range strings.Split(*timeZone, "/") {
828: 		if part == "." || part == ".." || strings.HasPrefix(part, "-") || !validTimeZoneCharacters.MatchString(part) {
829: 			allErrs = append(allErrs, field.Invalid(fldPath, timeZone, fmt.Sprintf("unknown time zone %s", *timeZone)))
830: 			return allErrs
831: 		}
832: 	}
833: 
834: 	if strings.EqualFold(*timeZone, "Local") {
835: 		allErrs = append(allErrs, field.Invalid(fldPath, timeZone, "timeZone must be an explicit time zone as defined in https://www.iana.org/time-zones"))
836: 	}
837: 
838: 	if _, err := time.LoadLocation(*timeZone); err != nil {
839: 		allErrs = append(allErrs, field.Invalid(fldPath, timeZone, err.Error()))
840: 	}
841: 
842: 	return allErrs
843: }
