845: // ValidateJobTemplateSpec validates a JobTemplateSpec and returns an ErrorList with any errors.
846: func ValidateJobTemplateSpec(spec *batch.JobTemplateSpec, fldPath *field.Path, opts apivalidation.PodValidationOptions) field.ErrorList {
847: 	allErrs := validateJobSpec(&spec.Spec, fldPath.Child("spec"), opts)
848: 
849: 	// jobtemplate will always have the selector automatically generated
850: 	if spec.Spec.Selector != nil {
851: 		allErrs = append(allErrs, field.Invalid(fldPath.Child("spec", "selector"), spec.Spec.Selector, "`selector` will be auto-generated"))
852: 	}
853: 	if spec.Spec.ManualSelector != nil && *spec.Spec.ManualSelector {
854: 		allErrs = append(allErrs, field.NotSupported(fldPath.Child("spec", "manualSelector"), spec.Spec.ManualSelector, []string{"nil", "false"}))
855: 	}
856: 	return allErrs
857: }
