859: func validateCompletions(spec, oldSpec batch.JobSpec, fldPath *field.Path, opts JobValidationOptions) field.ErrorList {
860: 	// Completions is immutable for non-indexed jobs, but mutable for Indexed Jobs.
861: 	isIndexedJob := spec.CompletionMode != nil && *spec.CompletionMode == batch.IndexedCompletion
862: 	if !isIndexedJob {
863: 		return apivalidation.ValidateImmutableField(spec.Completions, oldSpec.Completions, fldPath)
864: 	}
865: 
866: 	var allErrs field.ErrorList
867: 	if apiequality.Semantic.DeepEqual(spec.Completions, oldSpec.Completions) {
868: 		return allErrs
869: 	}
870: 	// Indexed Jobs cannot set completions to nil. The nil check
871: 	// is already performed in validateJobSpec, no need to add another error.
872: 	if spec.Completions == nil {
873: 		return allErrs
874: 	}
875: 
876: 	if *spec.Completions != *spec.Parallelism {
877: 		allErrs = append(allErrs, field.Invalid(fldPath, spec.Completions, fmt.Sprintf("can only be modified in tandem with %s", fldPath.Root().Child("parallelism").String())))
878: 	}
879: 	return allErrs
880: }
